class QLearningAgent: def __init__(self, state_size, action_size): self.q_table = np.zeros((state_size, action_size)) self-learning_rate = 0.1 selfdiscount_factor = 0.95 self.explorationprob \(= 0.9\)   
def choose_action(self,state): if random.uniform(0,1) \(< \) self.explorationprob: return random.choice(len(self.q_table[0])) # Explore else: return np.argmax(self.q_table[state]) # Exploit   
def learn(self,state,action,reward,next_state): if next_state is not None:# Only learn if next_state is not terminal best_next_action \(=\) np.argmax(self.q_table[next_state]) td_target \(=\) reward \(^+\) self(discount_factor\*self.q_table(next_state)[best_next_action] tdOTA \(=\) td_target-self.q_table[state][action] self.q_table[state][action] \(+ =\) self_learning_rate\*tdOTA

